mapper.select:
select student.id, student.name, student.no, student.gender, student.phone, student.id_card, student.is_college, student.address, student.degree, student.graduation_date, student.clazz_id, student.violation_count, student.violation_score, student.create_time, student.update_time, clazz.name clazz_name from student left join clazz on clazz_id = clazz.id

    
        student.name like concat('%',#{name},'%')
    
    
        and student.degree = #{degree}
    
    
       and student.clazz_id = #{clazzId}
